using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 10m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreSame(items, order.Items);
    }

    // --- CreateOrder: total calculation ---

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithVariousItems_CalculatesCorrectTotal(
        string description, (string name, decimal price, int qty)[] items, decimal expectedTotal)
    {
        var orderItems = CreateItems(items);

        var order = _service.CreateOrder("cust-1", orderItems);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(string description, (string, decimal, int)[] items, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single item", [("Widget", 25.50m, 2)], 51.00m),
        ("Multiple items", [("Widget", 10m, 1), ("Gadget", 20m, 3)], 70m),
        ("Single unit", [("Item", 99.99m, 1)], 99.99m),
    ];

    // --- CreateOrder: argument validation ---

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllForCustomer()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 20m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 30m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-999");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyOrdersForSpecifiedCustomer()
    {
        var order1 = _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("B", 20m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        var single = Assert.ContainsSingle(orders);
        Assert.AreSame(order1, single);
    }
}

